class Solution:
    def minimizeXor(self, num1: int, num2: int) -> int:
        def count_set_bits(n: int) -> int:
            return bin(n).count('1')

        set_bits_num2 = count_set_bits(num2)
        set_bits_num1 = count_set_bits(num1)

        if set_bits_num1 == set_bits_num2:
            return num1

        if set_bits_num1 > set_bits_num2:
            diff = set_bits_num1 - set_bits_num2
            mask = 1
            while diff > 0:
                if num1 & mask:
                    num1 ^= mask
                    diff -= 1
                mask <<= 1
            return num1

        mask = 1
        while set_bits_num1 < set_bits_num2:
            if not (num1 & mask):
                num1 ^= mask
                set_bits_num1 += 1
            mask <<= 1
            if mask > num1:
                break
        return num1
